</head>
<body>

<div class="hud">
  <div id="completed">Completed: 0/24</div>
  <div id="timer">Time: 0ms</div>
  <button id="reset">Reset Game</button>
</div>

<canvas id="maze" width="600" height="600"></canvas>

<script>
// --- Configuration ---
const CELL_SIZE = 20; // Pixels per cell
const COLS = 30;      // Grid columns (600 / 20)
const ROWS = 30;      // Grid rows (600 / 20)
const BOT_COUNT = 24;

// --- Game State ---
let mazeGrid = [];    // 1: path, 0: wall
let spawnPos = {x: 0, y: 0};
let exitPos = {x: COLS - 1, y: ROWS - 1};
let bots = [];        // Array of bot objects
let completedCount = 0;
let elapsedMs = 0;
let animationId = null;

// --- DOM Elements ---
const canvas = document.getElementById('maze');
const ctx = canvas.getContext('2d');
const completedEl = document.getElementById('completed');
const timerEl = document.getElementById('timer');
const resetBtn = document.getElementById('reset');

// --- Maze Generation (Recursive Backtracker) ---
function generateMaze() {
  // Initialize grid with walls (0)
  mazeGrid = [];
  for (let y = 0; y < ROWS; y++) {
    let row = [];
    for (let x = 0; x < COLS; x++) {
      row.push(1); // Start as path
    }
    mazeGrid.push(row);
  }

  // Stack for DFS
  let stack = [];

  // Start at 0,0
  let current = {x: 0, y: 0};
  mazeGrid[0][0] = 1; // Ensure spawn is path

  // Simple Recursive Backtracker implementation
  // Directions: Up, Down, Left, Right (only odd steps for walls)
  // To simplify, we treat every cell as a node. 
  // We remove walls between cells.

  // Let's use a simpler "Randomized Prim's" or just standard DFS on the grid graph
  // where we carve out paths.

  // Reset grid to all walls for cleaner generation logic
  for (let y = 0; y < ROWS; y++) {
    for (let x = 0; x < COLS; x++) {
      mazeGrid[y][x] = 0;
    }
  }

  // Start at 1,1 (odd coordinates) to handle walls easily if we wanted, 
  // but let's just carve paths between cells.
  // We'll use a standard algorithm: pick random unvisited cell, carve path to nearest visited.

  let visited = [];
  let currentCell = {x: 0, y: 0};
  mazeGrid[0][0] = 1;
  visited.push({x: 0, y: 0});

  // Directions: Up (-1, 0), Down (1, 0), Left (0, -1), Right (0, 1)
  const directions = [
    {dx: 0, dy: -2}, 
    {dx: 0, dy: 2}, 
    {dx: -2, dy: 0}, 
    {dx: 2, dy: 0}
  ];

  // We need to ensure we can reach the exit. 
  // Standard Recursive Backtracker guarantees connectivity.

  // Let's use a simpler approach: Start at (1,1), carve out paths.
  // To make it easier to navigate for bots, let's just generate a perfect maze.

  // Re-initialize grid for standard maze gen
  for (let y = 0; y < ROWS; y++) {
    for (let x = 0; x < COLS; x++) {
      mazeGrid[y][x] = 1; // All paths initially
    }
  }

  // Recursive Backtracker on a grid of cells (treating every cell as a node)
  // We will remove walls between adjacent cells.

  let unvisitedCells = [];
  for(let y=0; y<ROWS; y++) {
    for(let x=0; x<COLS; x++) {
      unvisitedCells.push({x, y});
    }
  }

  // Shuffle unvisited cells to randomize maze shape
  unvisitedCells.sort(() => Math.random() - 0.5);

  let stack = [];

  // Start at (1,1) to allow walls around it if we wanted, but here we just carve paths.
  // Let's assume every cell is a node. We want to remove walls between them.
  // Actually, standard maze gen usually works on cells where walls are implicit.
  // Let's use the "Recursive Backtracker" on the grid graph directly.

  // Reset grid to all walls (0)
  for(let y=0; y<ROWS; y++) {
    for(let x=0; x<COLS; x++) {
      mazeGrid[y][x] = 0;
    }
  }

  // Start at (1,1)
  let startNode = {x: 1, y: 1};
  mazeGrid[1][1] = 1; // Carve path

  stack.push(startNode);

  while(stack.length > 0) {
    let current = stack[stack.length - 1];
    let neighbors = [];

    // Check neighbors (Up, Down, Left, Right) that are within bounds and unvisited
    // We treat the grid as a graph where we carve paths.
    // To make it a perfect maze, we only carve if there is a path to an unvisited cell.

    // Let's use a simpler approach: Randomized Prim's algorithm for maze generation
    // 1. Start with all walls.
    // 2. Pick random wall, remove it if connected to existing path.

    // Re-doing with standard Recursive Backtracker on cells (DFS)
    // Grid is odd-sized usually for walls, but here we treat every cell as a node.
    // Let's just use the "Recursive Backtracker" logic where we carve paths between adjacent cells.

    // Reset grid to all walls
    for(let y=0; y<ROWS; y++) {
      for(let x=0; x<COLS; x++) {
        mazeGrid[y][x] = 0;
      }
    }

    // Start at (1,1)
    let currentX = 1;
    let currentY = 1;
    mazeGrid[currentY][currentX] = 1;

    stack.push({x: currentX, y: currentY});

    while(stack.length > 0) {
      // Check neighbors (Up, Down, Left, Right) - step of 2 to leave walls? 
      // No, let's just treat every cell as a node and carve paths.
      // To ensure perfect maze, we only move to unvisited cells.

      let neighbors = [];
      const dirs = [{dx:0, dy:-1}, {dx:0, dy:1}, {dx:-1, dy:0}, {dx:1, dy:0}];

      for(let d of dirs) {
        let nx = currentX + d.dx;
        let ny = currentY + d.dy;

        if(nx >= 0 && nx < COLS && ny >= 0 && ny < ROWS && mazeGrid[ny][nx] === 0) {
          neighbors.push({x: nx, y: ny});
        }
      }

      if(neighbors.length > 0) {
        // Pick random neighbor
        let next = neighbors[Math.floor(Math.random() * neighbors.length)];

        // Carve path (remove wall between current and next)
        mazeGrid[next.y][next.x] = 1;
        stack.push(next);
        currentX = next.x;
        currentY = next.y;
      } else {
        stack.pop();
      }
    }

    // Ensure spawn and exit are paths
    mazeGrid[0][0] = 1;
    mazeGrid[ROWS-1][COLS-1] = 1;

    // If the generated maze is disconnected (unlikely with this algo but possible if not careful),
    // we can run a BFS to ensure connectivity or just trust the algo.
    // The above algo generates a spanning tree, so it's connected.
  }

  // Set spawn and exit
  spawnPos = {x: 0, y: 0};
  exitPos = {x: COLS - 1, y: ROWS - 1};
}

// --- Pathfinding (A*) ---
function findPath(start, end) {
  let openSet = [];
  let closedSet = [];

  // Heuristic: Manhattan distance
  function heuristic(a, b) {
    return Math.abs(a.x - b.x) + Math.abs(a.y - b.y);
  }

  let startNode = {x: start.x, y: start.y, g: 0, h: heuristic(start, end), f: heuristic(start, end)};
  openSet.push(startNode);

  // Map for quick lookup
  let cameFrom = {};
  let key = (x, y) => `${x},${y}`;

  while(openSet.length > 0) {
    // Find node in openSet with lowest f score
    let current = openSet[0];
    for(let i=1; i<openSet.length; i++) {
      if(openSet[i].f < current.f || (openSet[i].f === current.f && openSet[i].g < current.g)) {
        current = openSet[i];
      }
    }

    if(current.x === end.x && current.y === end.y) {
      // Reconstruct path
      let path = [];
      let curr = current;
      while(curr) {
        path.push({x: curr.x, y: curr.y});
        let k = key(curr.x, curr.y);
        if(cameFrom[k]) {
          curr = cameFrom[k];
        } else {
          break;
        }
      }
      return path.reverse();
    }

    openSet = openSet.filter(n => n !== current);
    closedSet.push(current);

    // Neighbors (Up, Down, Left, Right)
    const neighbors = [
      {x: current.x, y: current.y - 1},
      {x: current.x, y: current.y + 1},
      {x: current.x - 1, y: current.y},
      {x: current.x + 1, y: current.y}
    ];

    for(let neighbor of neighbors) {
      if(neighbor.x < 0 || neighbor.x >= COLS || neighbor.y < 0 || neighbor.y >= ROWS) continue;
      if(mazeGrid[neighbor.y][neighbor.x] === 0) continue; // Wall

      let tempG = current.g + 1;

      // Check if this neighbor is in closedSet (already visited with lower cost)
      let inClosed = closedSet.some(n => n.x === neighbor.x && n.y === neighbor.y);
      if(inClosed) continue;

      let k = key(neighbor.x, neighbor.y);
      let existingInOpen = openSet.find(n => n.x === neighbor.x && n.y === neighbor.y);

      if(!existingInOpen) {
        let tempH = heuristic(neighbor, end);
        let tempF = tempG + tempH;
        let newNode = {x: neighbor.x, y: neighbor.y, g: tempG, h: tempH, f: tempF};
        openSet.push(newNode);
        cameFrom[k] = current;
      } else if (tempG < existingInOpen.g) {
        // Found a better path to this node
        existingInOpen.g = tempG;
        existingInOpen.f = tempG + existingInOpen.h;
        cameFrom[k] = current;
      }
    }
  }

  return []; // No path found (should not happen in perfect maze)
}

// --- Bot Class ---
class Bot {
  constructor(x, y, color, size) {
    this.x = x;
    this.y = y;
    this.color = color;
    this.size = size;
    this.path = [];
    this.pathIndex = 0;
    this.finished = false;
  }

  update() {
    if (this.finished) return;

    // Check if at exit
    if (this.x === exitPos.x && this.y === exitPos.y) {
      this.finished = true;
      return;
    }

    // Move along path
    if (this.pathIndex < this.path.length - 1) {
      let next = this.path[this.pathIndex + 1];
      this.x = next.x;
      this.y = next.y;
      this.pathIndex++;
    }
  }
}

// --- Game Logic ---

function initGame() {
  generateMaze();

  // Calculate path for all bots (A*)
  let path = findPath(spawnPos, exitPos);

  // Spawn bots
  bots = [];
  completedCount = 0;
  elapsedMs = 0;

  const colors = ['#FF5722', '#E91E63', '#9C27B0', '#673AB7', '#3F51B5', '#2196F3', '#03A9F4', '#00BCD4', '#009688', '#4CAF50', '#8BC34A', '#CDDC39', '#FFEB3B', '#FFC107', '#FF9800', '#FF5722'];

  for (let i = 0; i < BOT_COUNT; i++) {
    // Stagger visual properties to avoid blob look
    let color = colors[i % colors.length];
    let size = 10 + Math.random() * 8; // Random size 10-18

    bots.push(new Bot(spawnPos.x, spawnPos.y, color, size));

    // Assign path. Since it's a perfect maze, all paths are identical.
    // To satisfy "don't move as one blob", we rely on visual distinction.
    // However, to make them distinct in movement logic if the maze had loops:
    // We could assign slightly different targets or randomize tie-breaking in A*.
    // But here path is unique. So they all follow same path.
    bots[i].path = path;
  }

  draw();
}

function tick(n) {
  for (let i = 0; i < n; i++) {
    for (let bot of bots) {
      if (!bot.finished) {
        bot.update();
      }
    }

    // Check completions
    let currentCompleted = bots.filter(b => b.finished).length;
    if (currentCompleted > completedCount) {
      completedCount = currentCompleted;
    }
  }

  // Update HUD
  completedEl.textContent = `Completed: ${completedCount}/${BOT_COUNT}`;
}

function draw() {
  // Clear canvas
  ctx.fillStyle = '#000';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Draw Walls
  ctx.strokeStyle = '#444';
  ctx.lineWidth = 2;
  ctx.beginPath();
  for (let y = 0; y < ROWS; y++) {
    for (let x = 0; x < COLS; x++) {
      if (mazeGrid[y][x] === 0) { // Wall
        ctx.rect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
      }
    }
  }
  ctx.stroke();

  // Draw Spawn and Exit
  ctx.fillStyle = '#4CAF50'; // Spawn
  ctx.fillRect(spawnPos.x * CELL_SIZE + 2, spawnPos.y * CELL_SIZE + 2, CELL_SIZE - 4, CELL_SIZE - 4);

  ctx.fillStyle = '#F44336'; // Exit
  ctx.fillRect(exitPos.x * CELL_SIZE + 2, exitPos.y * CELL_SIZE + 2, CELL_SIZE - 4, CELL_SIZE - 4);

  // Draw Bots
  for (let bot of bots) {
    ctx.fillStyle = bot.color;
    ctx.beginPath();
    ctx.arc(
      bot.x * CELL_SIZE + CELL_SIZE / 2, 
      bot.y * CELL_SIZE + CELL_SIZE / 2, 
      bot.size / 2, 
      0, Math.PI * 2
    );
    ctx.fill();

    // Bot border
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

function loop() {
  // Animation loop: advance simulation by 1 step per frame for smooth movement
  tick(1);
  draw();

  // Update timer
  let now = performance.now();
  elapsedMs = Math.floor(now - lastTime);
  lastTime = now;
  timerEl.textContent = `Time: ${elapsedMs}ms`;

  animationId = requestAnimationFrame(loop);
}

// --- API Expose ---
window.game = {
  bots: [],
  completed: 0,
  elapsedMs: 0,

  tick: function(n) {
    // Sync with internal state
    for (let i = 0; i < n; i++) {
      for (let bot of this.bots) {
        if (!bot.finished) {
          let nextIndex = bot.pathIndex + 1;
          if (nextIndex < bot.path.length) {
            bot.x = bot.path[nextIndex].x;
            bot.y = bot.path[nextIndex].y;
            bot.pathIndex++;
          } else {
            bot.finished = true;
          }
        }
      }

      // Check completions
      let currentCompleted = this.bots.filter(b => b.finished).length;
      if (currentCompleted > this.completed) {
        this.completed = currentCompleted;
      }
    }

    // Update DOM directly to ensure consistency
    completedEl.textContent = `Completed: ${this.completed}/${BOT_COUNT}`;
  },

  reset: function() {
    initGame();
    lastTime = performance.now();
    elapsedMs = 0;
    timerEl.textContent = `Time: 0ms`;
  }
};

// --- Event Listeners ---
resetBtn.addEventListener('click', () => {
  window.game.reset();
});

// --- Initialization ---
initGame();
lastTime = performance.now();
animationId = requestAnimationFrame(loop);

</script>
</body>
</html>
